head.script:
//
(function(){
  try {
    var saved = localStorage.getItem('cm-theme');
    var pref = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
    var mode = saved || (pref ? 'dark' : 'light');
    document.documentElement.setAttribute('data-theme', mode);
  } catch(e){ document.documentElement.setAttribute('data-theme','light'); }
})();
//

head.b:skin:
/*
<Variable name="accent" description="Accent color" type="color" default="#0f7a6c" value="#0f7a6c"/>
<Variable name="accent.dark" description="Accent color (dark)" type="color" default="#5fd1be" value="#5fd1be"/>
*/

/* ── Reset ───────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; }
html, body { margin: 0; padding: 0; }
img { max-width: 100%; height: auto; display: block; }
a { color: inherit; text-decoration: none; }
ul, ol { padding: 0; margin: 0; list-style: none; }
button { font: inherit; cursor: pointer; }
.hidden, .item-control { display: none; }

/* ── Tokens ──────────────────────────────────────────── */
:root, [data-theme='light'] {
  --bg:        #f4f5f1;
  --surface:   #ffffff;
  --surface-2: #eceee8;
  --ink:       #0e1410;
  --body:      #3a4640;
  --muted:     #737d76;
  --rule:      #dfe2dc;
  --accent:    #0f7a6c;
  --accent-soft:#dbeae6;
  --accent-ink:#08201c;
  --code-bg:   #0d1410;
  --code-ink:  #e6e7df;
  --code-mute: #6b7872;
  --chip-bg:   #eaede5;
  --chip-ink:  #3a4640;
  --shadow:    0 1px 2px rgba(20,30,25,0.04), 0 4px 16px rgba(20,30,25,0.04);
}
[data-theme='dark'] {
  --bg:        #0f1311;
  --surface:   #171c19;
  --surface-2: #1c2320;
  --ink:       #f0f4ee;
  --body:      #c4ccc6;
  --muted:     #7d877f;
  --rule:      #262d29;
  --accent:    #5fd1be;
  --accent-soft:#1c2e2a;
  --accent-ink:#08201c;
  --code-bg:   #0a0d0b;
  --code-ink:  #e6f0eb;
  --code-mute: #6b7872;
  --chip-bg:   #1c2320;
  --chip-ink:  #a8b3ac;
  --shadow:    0 1px 2px rgba(0,0,0,0.25), 0 6px 24px rgba(0,0,0,0.25);
}

/* ── Base ────────────────────────────────────────────── */
html { background: var(--bg); }
body {
  background: var(--bg);
  color: var(--body);
  font-family: 'Manrope', -apple-system, BlinkMacSystemFont, system-ui, sans-serif;
  font-size: 16px;
  line-height: 1.7;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
  min-height: 100vh;
  overflow-wrap: break-word;
}
.mono { font-family: 'JetBrains Mono', ui-monospace, monospace; }
::selection { background: var(--accent); color: var(--accent-ink); }

/* ── Layout ──────────────────────────────────────────── */
.container { max-width: 1240px; margin: 0 auto; padding: 0 32px; }
.container-narrow { max-width: 1080px; margin: 0 auto; padding: 0 32px; }

/* ── Header ──────────────────────────────────────────── */
.site-header {
  background: var(--bg);
  border-bottom: 1px solid var(--rule);
  position: sticky;
  top: 0;
  z-index: 50;
  backdrop-filter: saturate(150%) blur(8px);
  -webkit-backdrop-filter: saturate(150%) blur(8px);
}
.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
  padding: 14px 0 14px 16px;
}
.brand { display: flex; align-items: center; gap: 10px; }
.brand-logo {
  width: 30px; height: 30px; border-radius: 8px;
  background: var(--ink); color: var(--bg);
  display: grid; place-items: center;
  font-family: 'JetBrains Mono', monospace; font-weight: 700; font-size: 15px;
  letter-spacing: -0.04em;
}
.brand-name { font-weight: 800; font-size: 18px; color: var(--ink); letter-spacing: -0.015em; }
.brand-version { font-family: 'JetBrains Mono', monospace; font-size: 11px; color: var(--muted); padding-left: 10px; border-left: 1px solid var(--rule); }

.site-nav { display: flex; align-items: center; gap: 28px; font-size: 14px; font-weight: 500; }
.site-nav a { color: var(--body); transition: color .15s; padding: 4px 0; }
.site-nav a:hover, .site-nav a.is-active { color: var(--ink); }

.header-actions { display: flex; align-items: center; gap: 10px; }
.search-trigger {
  display: flex; align-items: center; gap: 8px;
  padding: 7px 12px;
  background: var(--surface);
  border: 1px solid var(--rule);
  border-radius: 10px;
  color: var(--muted);
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  min-width: 200px;
  cursor: pointer;
  transition: border-color .15s, background .15s;
}
.search-trigger:hover { border-color: var(--accent); }
.search-trigger .kbd {
  margin-left: auto;
  padding: 1px 6px;
  border-radius: 4px;
  background: var(--bg);
  border: 1px solid var(--rule);
  font-size: 10px;
}
.theme-switch {
  display: flex; align-items: center; padding: 4px;
  background: var(--surface); border: 1px solid var(--rule);
  border-radius: 999px;
}
.theme-switch button {
  width: 28px; height: 28px; border-radius: 999px;
  border: 0; background: transparent;
  color: var(--muted);
  display: grid; place-items: center;
  transition: background .15s, color .15s;
}
.theme-switch button.is-active { background: var(--ink); color: var(--bg); }
.theme-switch svg { width: 14px; height: 14px; }

/* ── Mobile nav ──────────────────────────────────────── */
.menu-toggle { display: none; background: transparent; border: 0; padding: 8px; color: var(--ink); }
@media (max-width: 900px) {
  .header-inner { gap: 12px; }
  .site-nav, .search-trigger { display: none; }
  .menu-toggle { display: grid; place-items: center; }
  .brand-version { display: none; }
  body.menu-open .site-nav {
    display: flex;
    position: fixed; inset: 56px 0 0 0;
    background: var(--bg);
    flex-direction: column;
    align-items: flex-start;
    padding: 24px 32px;
    gap: 18px;
    font-size: 18px;
    z-index: 40;
  }
}

/* ── Hero (homepage) ─────────────────────────────────── */
.hero { padding: 56px 0 24px; }
.hero-grid {
  display: grid;
  grid-template-columns: 1.05fr 1fr;
  gap: 48px;
  align-items: center;
}
.hero-kicker {
  display: inline-flex; align-items: center; gap: 10px;
  padding: 5px 12px 5px 8px;
  background: var(--accent-soft);
  color: var(--accent);
  border-radius: 999px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  margin-bottom: 24px;
}
.hero-kicker .dot { width: 6px; height: 6px; border-radius: 50%; background: var(--accent); }
.hero-title {
  margin: 0 0 18px;
  font-weight: 700; font-size: clamp(34px, 5.4vw, 56px);
  line-height: 1.05;
  letter-spacing: -0.025em;
  color: var(--ink);
  text-wrap: balance;
}
.hero-title a { color: inherit; }
.hero-title a:hover { color: var(--accent); }
.hero-excerpt {
  margin: 0 0 28px;
  font-size: 18px; line-height: 1.6;
  color: var(--body); max-width: 540px;
  text-wrap: pretty;
}
.hero-actions { display: flex; align-items: center; gap: 16px; flex-wrap: wrap; }
.btn-primary {
  display: inline-flex; align-items: center; gap: 10px;
  padding: 11px 18px 11px 20px;
  background: var(--ink); color: var(--bg);
  border: 0; border-radius: 8px;
  font-weight: 600; font-size: 14px;
  transition: transform .15s, opacity .15s;
}
.btn-primary:hover { transform: translateY(-1px); opacity: .92; }
.hero-meta { display: flex; align-items: center; gap: 8px; font-family: 'JetBrains Mono', monospace; font-size: 12px; color: var(--muted); }
.hero-meta a:hover { color: var(--accent); }
.hero-image {
  border-radius: 16px; overflow: hidden;
  border: 1px solid var(--rule);
  background: var(--surface);
  padding: 14px;
}
.hero-image img, .hero-image .featured-fallback { width: 100%; height: 360px; border-radius: 8px; object-fit: cover; }
.featured-fallback {
  background-image: repeating-linear-gradient(45deg, var(--accent-soft) 0 14px, var(--surface-2) 14px 28px);
  display: grid; place-items: center;
  color: var(--accent);
  font-family: 'JetBrains Mono', monospace; font-size: 12px; letter-spacing: 0.08em;
}

@media (max-width: 900px) {
  .hero-grid { grid-template-columns: 1fr; gap: 28px; }
  .hero-image img, .hero-image .featured-fallback { height: 240px; }
}

/* ── Tag filter strip ────────────────────────────────── */
.tag-strip {
  padding: 18px 0;
  border-top: 1px solid var(--rule);
  border-bottom: 1px solid var(--rule);
  display: flex; align-items: center; gap: 12px; flex-wrap: wrap;
}
.tag-strip-label {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  color: var(--muted);
  margin-right: 4px;
}
.tag-chip {
  padding: 6px 12px;
  border-radius: 999px;
  border: 1px solid var(--rule);
  background: transparent;
  color: var(--body);
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  transition: border-color .15s, color .15s, background .15s;
}
.tag-chip:hover { border-color: var(--ink); color: var(--ink); }
.tag-chip.is-active { background: var(--ink); color: var(--bg); border-color: var(--ink); }

/* ── Main grid ───────────────────────────────────────── */
.page-outer {
  max-width: 1240px;
  margin: 0 auto;
  padding: 40px 32px 80px;
}
.posts-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 24px;
}
body.feed-view .page-outer {
  display: grid;
  grid-template-columns: 1fr 300px;
  gap: 48px;
  align-items: start;
}
@media (max-width: 900px) {
  body.feed-view .page-outer { grid-template-columns: 1fr; }
}
body.item-view .page-outer { max-width: none; padding: 0; }
body.item-view .page-outer > .sidebar { display: none; }

.post-card {
  background: var(--surface);
  border: 1px solid var(--rule);
  border-radius: 14px;
  padding: 18px;
  display: flex; flex-direction: column; gap: 14px;
  transition: transform .15s, box-shadow .15s, border-color .15s;
}
.post-card:hover { transform: translateY(-2px); box-shadow: var(--shadow); border-color: var(--accent); }
.post-card-cover {
  aspect-ratio: 16 / 9;
  border-radius: 8px;
  overflow: hidden;
  background: var(--surface-2);
  display: block;
}
.post-card-cover img { width: 100%; height: 100%; object-fit: cover; }
.post-card-cover .featured-fallback { width: 100%; height: 100%; border-radius: 0; }
.post-card-meta {
  display: flex; align-items: center; gap: 10px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 11.5px;
  color: var(--muted);
}
.post-card-meta .sep { width: 3px; height: 3px; border-radius: 50%; background: var(--muted); }
.post-card-title {
  margin: 0;
  font-weight: 700; font-size: 22px;
  line-height: 1.18;
  letter-spacing: -0.018em;
  color: var(--ink);
  text-wrap: pretty;
}
.post-card-title a:hover { color: var(--accent); }
.post-card-excerpt {
  margin: 0;
  font-size: 14.5px; line-height: 1.55;
  color: var(--body);
  text-wrap: pretty;
  display: -webkit-box;
  -webkit-line-clamp: 4;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.post-card-foot {
  display: flex; align-items: center; justify-content: space-between;
  margin-top: auto; padding-top: 8px;
}
.tag-pill {
  display: inline-flex; align-items: center; gap: 4px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  padding: 3px 8px;
  border-radius: 6px;
  background: var(--chip-bg);
  color: var(--chip-ink);
  margin-right: 4px;
}
.tag-pill:hover { background: var(--accent-soft); color: var(--accent); }
.post-card-read {
  display: inline-flex; align-items: center; gap: 6px;
  color: var(--accent);
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  font-weight: 500;
}

/* ── Sidebar ─────────────────────────────────────────── */
.sidebar { display: grid; gap: 22px; align-content: start; }
.sidebar-card {
  background: var(--surface);
  border: 1px solid var(--rule);
  border-radius: 14px;
  padding: 22px;
}
.sidebar-card .title {
  margin: 0 0 14px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 11.5px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--muted);
  font-weight: 500;
}
.sidebar-card ul li { padding: 8px 0; font-size: 14px; border-bottom: 1px dashed var(--rule); }
.sidebar-card ul li:last-child { border-bottom: 0; }
.sidebar-card ul li a { color: var(--body); }
.sidebar-card ul li a:hover { color: var(--accent); }
.sidebar-card .post-count, .sidebar-card .label-count { float: right; color: var(--muted); font-family: 'JetBrains Mono', monospace; font-size: 12px; }
.sidebar-card .post-count::before, .sidebar-card .label-count::before { content: "("; }
.sidebar-card .post-count::after, .sidebar-card .label-count::after { content: ")"; }

/* Profile widget */
.widget.Profile .profile-img,
.widget.Profile .default-avatar-wrapper {
  width: 44px; height: 44px;
  border-radius: 12px;
  overflow: hidden;
  background: linear-gradient(135deg, var(--accent), color-mix(in oklab, var(--accent) 30%, #000));
  margin-right: 12px;
  float: left;
}
.widget.Profile .default-avatar-wrapper svg, .widget.Profile .avatar-icon {
  width: 100%; height: 100%; fill: var(--bg);
}
.widget.Profile .profile-name { font-weight: 700; color: var(--ink); }
.widget.Profile .profile-description { font-size: 14px; line-height: 1.55; clear: both; padding-top: 10px; }
.widget.Profile a.profile-link { display: inline-block; margin-top: 10px; color: var(--accent); font-family: 'JetBrains Mono', monospace; font-size: 12px; }

/* Label cloud */
.widget.Label ul { display: flex; flex-wrap: wrap; gap: 6px; }
.widget.Label li { border: 0; padding: 0; }
.widget.Label li a {
  display: inline-flex; align-items: center; gap: 6px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  padding: 5px 10px;
  border-radius: 999px;
  background: var(--chip-bg);
  color: var(--chip-ink);
  transition: background .15s, color .15s;
}
.widget.Label li a:hover { background: var(--accent); color: var(--accent-ink); }

/* ── Post (item view) ────────────────────────────────── */
.post-view { padding: 48px 0 24px; }
.breadcrumb {
  display: flex; align-items: center; gap: 10px;
  font-family: 'JetBrains Mono', monospace; font-size: 12px;
  color: var(--muted); margin-bottom: 18px; flex-wrap: wrap;
}
.breadcrumb a { color: var(--muted); }
.breadcrumb a:hover { color: var(--ink); }
.breadcrumb .current { color: var(--accent); }

.post-title-h1 {
  margin: 0 0 22px;
  font-weight: 800; font-size: clamp(32px, 5vw, 52px);
  line-height: 1.04;
  letter-spacing: -0.025em;
  color: var(--ink);
  text-wrap: balance;
}
.post-deck {
  margin: 0 0 24px;
  font-size: 20px; line-height: 1.55;
  color: var(--body);
  max-width: 760px;
  text-wrap: pretty;
}
.post-author-strip {
  display: flex; align-items: center; gap: 16px; flex-wrap: wrap;
  font-family: 'JetBrains Mono', monospace; font-size: 12.5px; color: var(--muted);
}
.post-author-strip .avatar {
  width: 28px; height: 28px; border-radius: 8px; overflow: hidden;
  background: linear-gradient(135deg, var(--accent), color-mix(in oklab, var(--accent) 30%, #000));
  display: grid; place-items: center;
  color: var(--accent-ink); font-weight: 800; font-size: 13px;
}
.post-author-strip .avatar img { width: 100%; height: 100%; object-fit: cover; }
.post-author-strip .author-name { color: var(--ink); }
.post-author-strip .sep { width: 3px; height: 3px; border-radius: 50%; background: var(--muted); }
.post-author-strip .comments-link { color: var(--accent); }

.post-cover-wrap { padding: 12px 0; margin: 0 auto; }
.post-cover {
  border-radius: 16px;
  overflow: hidden;
  border: 1px solid var(--rule);
  background: var(--surface-2);
  aspect-ratio: 21 / 9;
}
.post-cover img { width: 100%; height: 100%; object-fit: cover; }

.post-layout {
  display: grid;
  grid-template-columns: 220px 1fr;
  gap: 56px;
  align-items: start;
  padding: 32px 0;
}
@media (max-width: 1024px) { .post-layout { grid-template-columns: 1fr; gap: 24px; } }
.post-layout.no-toc { grid-template-columns: 1fr; }
.post-layout.no-toc .post-toc { display: none; }

.post-toc { position: sticky; top: 80px; }
.post-toc-title {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 16px;
}
.post-toc ul { display: grid; gap: 10px; font-size: 13.5px; }
.post-toc ul li {
  padding-left: 14px;
  border-left: 2px solid var(--rule);
  color: var(--body);
  cursor: pointer;
  line-height: 1.4;
}
.post-toc ul li:hover { color: var(--ink); }
.post-toc ul li.is-active { border-left-color: var(--accent); color: var(--ink); font-weight: 600; }
.post-toc-progress {
  margin-top: 28px;
  padding: 14px;
  background: var(--surface);
  border: 1px solid var(--rule);
  border-radius: 10px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 11.5px;
  color: var(--muted);
}
.post-toc-progress .progress-label { color: var(--ink); margin-bottom: 6px; letter-spacing: 0.1em; text-transform: uppercase; }
.progress-bar { height: 4px; background: var(--rule); border-radius: 999px; overflow: hidden; }
.progress-bar-fill { height: 100%; background: var(--accent); width: 0; transition: width .2s; }
@media (max-width: 1024px) { .post-toc { display: none; } }

/* ── Post body typography ────────────────────────────── */
.post-body {
  font-size: 17px; line-height: 1.75; color: var(--body);
  max-width: 720px;
}
.post-body p { margin: 0 0 22px; text-wrap: pretty; }
.post-body h2 {
  margin: 40px 0 14px;
  font-weight: 700; font-size: 28px;
  color: var(--ink);
  letter-spacing: -0.015em;
}
.post-body h3 {
  margin: 32px 0 10px;
  font-weight: 700; font-size: 22px;
  color: var(--ink);
}
.post-body h4 {
  margin: 24px 0 10px;
  font-weight: 600; font-size: 18px;
  color: var(--ink);
}
.post-body a {
  color: var(--accent);
  text-decoration: underline;
  text-decoration-thickness: 1px;
  text-underline-offset: 3px;
}
.post-body a:hover { text-decoration-thickness: 2px; }
.post-body strong { color: var(--ink); font-weight: 600; }
.post-body em { color: var(--ink); }
.post-body ul, .post-body ol { margin: 0 0 22px; padding-left: 24px; }
.post-body ul li { list-style: disc; margin: 6px 0; }
.post-body ol li { list-style: decimal; margin: 6px 0; }
.post-body img {
  border-radius: 10px;
  margin: 24px 0;
  border: 1px solid var(--rule);
}
.post-body hr {
  border: 0;
  height: 1px;
  background: var(--rule);
  margin: 36px 0;
}

/* Inline code */
.post-body :not(pre) > code {
  font-family: 'JetBrains Mono', monospace;
  font-size: 0.88em;
  background: var(--surface);
  color: var(--accent);
  padding: 2px 7px;
  border-radius: 5px;
  border: 1px solid var(--rule);
}

/* Block code */
.post-body pre {
  margin: 28px 0;
  border-radius: 12px;
  overflow: hidden;
  background: var(--code-bg);
  border: 1px solid var(--rule);
  padding: 0;
}
.post-body pre code {
  display: block;
  padding: 20px 22px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 13.5px;
  line-height: 1.65;
  color: var(--code-ink);
  background: transparent;
  border: 0;
  overflow-x: auto;
  white-space: pre;
}

/* Decorated code block */
.code-block {
  margin: 28px 0;
  border-radius: 12px;
  overflow: hidden;
  background: var(--code-bg);
  border: 1px solid var(--rule);
}
.code-block-head {
  display: flex; align-items: center; justify-content: space-between;
  padding: 12px 16px;
  background: rgba(255,255,255,0.02);
  border-bottom: 1px solid rgba(255,255,255,0.05);
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  color: var(--code-mute);
}
.code-block-head .dots { display: flex; gap: 6px; }
.code-block-head .dots span { width: 10px; height: 10px; border-radius: 50%; display: inline-block; }
.code-block-head .dots span:nth-child(1) { background: #ff5f57; }
.code-block-head .dots span:nth-child(2) { background: #febc2e; }
.code-block-head .dots span:nth-child(3) { background: #28c840; }
.code-block-head .lang {
  padding: 2px 7px;
  border-radius: 999px;
  background: rgba(95, 209, 190, 0.12);
  color: var(--accent);
  font-size: 10.5px;
  text-transform: uppercase;
  letter-spacing: 0.1em;
}
.code-block-head .copy-btn {
  background: transparent;
  border: 0;
  color: var(--code-mute);
  font-family: inherit;
  font-size: 11.5px;
  cursor: pointer;
  transition: color .15s;
}
.code-block-head .copy-btn:hover { color: var(--accent); }
.code-block pre { margin: 0; border: 0; border-radius: 0; }

/* Blockquote */
.post-body blockquote {
  margin: 32px 0;
  padding: 20px 24px;
  background: var(--surface);
  border-left: 3px solid var(--accent);
  border-radius: 0 10px 10px 0;
  font-size: 18px;
  line-height: 1.55;
  color: var(--ink);
  font-style: normal;
}
.post-body blockquote p:last-child { margin-bottom: 0; }
.post-body blockquote::before { content: ""; }

/* Tables */
.post-body table {
  width: 100%;
  border-collapse: collapse;
  margin: 24px 0;
  font-size: 14.5px;
}
.post-body table th, .post-body table td {
  padding: 10px 14px;
  text-align: left;
  border-bottom: 1px solid var(--rule);
}
.post-body table th { color: var(--ink); font-weight: 600; background: var(--surface); }

/* Post labels (tags) */
.post-labels {
  display: flex; flex-wrap: wrap; gap: 8px;
  margin-top: 36px; padding-top: 28px;
  border-top: 1px solid var(--rule);
}
.post-labels a {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  padding: 5px 11px;
  border-radius: 999px;
  background: var(--chip-bg);
  color: var(--chip-ink);
  border: 1px solid var(--rule);
}
.post-labels a:hover { border-color: var(--accent); color: var(--accent); }

/* ── Author bio block ────────────────────────────────── */
.author-bio {
  margin: 36px 0 24px;
  padding: 28px;
  background: var(--surface);
  border: 1px solid var(--rule);
  border-radius: 16px;
  display: grid;
  grid-template-columns: 120px 1fr auto;
  gap: 28px;
  align-items: center;
}
@media (max-width: 700px) {
  .author-bio { grid-template-columns: 1fr; }
  .author-bio-avatar { width: 80px; height: 80px; font-size: 36px; }
}
.author-bio-avatar {
  width: 120px; height: 120px;
  border-radius: 20px;
  overflow: hidden;
  background: linear-gradient(135deg, var(--accent), color-mix(in oklab, var(--accent) 30%, #000));
  display: grid; place-items: center;
  color: var(--accent-ink);
  font-weight: 800; font-size: 52px;
}
.author-bio-avatar img { width: 100%; height: 100%; object-fit: cover; }
.author-bio-kicker {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--accent);
  margin-bottom: 8px;
}
.author-bio h3 {
  margin: 0 0 8px;
  font-weight: 700; font-size: 26px;
  color: var(--ink);
}
.author-bio p {
  margin: 0 0 12px;
  font-size: 15px; line-height: 1.55;
  color: var(--body);
  max-width: 540px;
  text-wrap: pretty;
}
.author-bio-links {
  display: flex; gap: 16px; flex-wrap: wrap;
  font-family: 'JetBrains Mono', monospace;
  font-size: 12.5px; color: var(--muted);
}
.author-bio-links a { color: var(--body); }
.author-bio-links a:hover { color: var(--accent); }
.author-bio-cta { display: flex; flex-direction: column; gap: 8px; }
.author-bio-cta .btn-primary { background: var(--accent); color: var(--accent-ink); }
.author-bio-cta .btn-ghost {
  padding: 10px 18px;
  background: transparent;
  color: var(--body);
  border: 1px solid var(--rule);
  border-radius: 10px;
  font-weight: 600;
  font-size: 13px;
  text-align: center;
}
.author-bio-cta .btn-ghost:hover { border-color: var(--accent); color: var(--accent); }

/* ── Comments ────────────────────────────────────────── */
#comments {
  margin-top: 48px;
  padding-top: 32px;
  border-top: 1px solid var(--rule);
}
#comments h3 {
  margin: 0 0 24px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 11.5px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--muted);
}
#comments .comment {
  padding: 18px 0;
  border-bottom: 1px dashed var(--rule);
  list-style: none;
}
#comments .comment .user { color: var(--ink); font-weight: 600; }
#comments .comment .datetime {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  color: var(--muted);
  margin-left: 10px;
}
#comments .avatar-image-container img,
#comments .avatar-image-container .avatar-icon {
  border-radius: 8px;
  width: 36px; height: 36px;
}

/* ── Adjacent reading (related) ──────────────────────── */
.adjacent { padding: 24px 0 80px; }
.adjacent-head {
  display: flex; align-items: center; justify-content: space-between;
  margin-bottom: 18px;
}
.adjacent-head h3 {
  margin: 0;
  font-weight: 700; font-size: 20px;
  color: var(--ink);
}
.adjacent-head a {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12.5px;
  color: var(--accent);
}
.adjacent-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 20px;
}
@media (max-width: 900px) { .adjacent-grid { grid-template-columns: 1fr; } }
.adjacent-card {
  background: var(--surface);
  border: 1px solid var(--rule);
  border-radius: 12px;
  padding: 18px;
  display: flex; flex-direction: column; gap: 10px;
  transition: transform .15s, border-color .15s;
}
.adjacent-card:hover { transform: translateY(-2px); border-color: var(--accent); }
.adjacent-card .meta {
  display: flex; align-items: center; gap: 8px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 11.5px; color: var(--muted);
}
.adjacent-card h4 {
  margin: 0;
  font-weight: 700; font-size: 17px;
  line-height: 1.25;
  color: var(--ink);
  text-wrap: pretty;
}
.adjacent-card .read {
  margin-top: 6px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  color: var(--accent);
}

/* ── Pager ───────────────────────────────────────────── */
.blog-pager {
  display: flex; justify-content: space-between; align-items: center; gap: 16px;
  padding: 32px 0;
  border-top: 1px solid var(--rule);
  margin-top: 32px;
}
.blog-pager a {
  display: inline-flex; align-items: center; gap: 8px;
  padding: 10px 16px;
  border: 1px solid var(--rule);
  border-radius: 10px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
  color: var(--ink);
  background: var(--surface);
  transition: border-color .15s, color .15s;
}
.blog-pager a:hover { border-color: var(--accent); color: var(--accent); }
.blog-pager a[id$='blog-pager-newer-link'] { margin-right: auto; }
.blog-pager a[id$='blog-pager-older-link'] { margin-left: auto; }

/* Suppress Blogger's built-in pager injected inside the posts grid by super.main */
.posts-grid .blog-pager { display: none !important; }

/* ── Footer ──────────────────────────────────────────── */
.site-footer {
  background: var(--surface-2);
  border-top: 1px solid var(--rule);
  margin-top: 40px;
}
.footer-inner {
  display: grid;
  grid-template-columns: 1.6fr 1fr 1fr 1fr;
  gap: 36px;
  padding: 40px 16px 40px 0;
  align-items: start;
}
@media (max-width: 800px) { .footer-inner { grid-template-columns: 1fr 1fr; gap: 24px; } }
.footer-brand {
  padding-left: 16px;
}
.footer-brand p {
  margin: 12px 0 16px;
  font-size: 14px; line-height: 1.6;
  color: var(--body); max-width: 360px;
}
.footer-brand .colophon {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11.5px; color: var(--muted);
}
.footer-col h4 {
  margin: 0 0 12px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 11.5px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--muted);
  font-weight: 500;
}
.footer-col ul { display: grid; gap: 9px; font-size: 14px; }
.footer-col a { color: var(--body); }
.footer-col a:hover { color: var(--accent); }

/* ── Search overlay ──────────────────────────────────── */
.search-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.4);
  backdrop-filter: blur(4px);
  z-index: 100;
  display: none;
  padding-top: 96px;
}
.search-overlay.is-open { display: block; }
.search-modal {
  max-width: 600px;
  margin: 0 auto;
  background: var(--surface);
  border: 1px solid var(--rule);
  border-radius: 14px;
  box-shadow: var(--shadow);
  overflow: hidden;
}
.search-modal form {
  display: flex; align-items: center; gap: 12px;
  padding: 14px 18px;
  border-bottom: 1px solid var(--rule);
}
.search-modal input {
  flex: 1;
  background: transparent;
  border: 0;
  outline: 0;
  color: var(--ink);
  font-family: 'Manrope', sans-serif;
  font-size: 16px;
}
.search-modal input::placeholder { color: var(--muted); }
.search-modal .hint {
  padding: 10px 18px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  color: var(--muted);
}

/* ── Misc ────────────────────────────────────────────── */
.no-posts-message { padding: 60px 0; text-align: center; color: var(--muted); }
iframe.b-hbp-video { border: 0; }
.blogger-logo, .svg-icon-24.blogger-logo { fill: var(--muted); opacity: .5; }
/* Attribution widget inside footer — shrink Blogger icon to match link style */
.footer-attribution .widget-content { all: unset; }
.footer-attribution .blogger { display: block; }
.footer-attribution .blogger a {
  display: inline-flex; align-items: center; gap: 6px;
  font-size: 14px; color: var(--body); text-decoration: none;
}
.footer-attribution .blogger a:hover { color: var(--accent); }
.footer-attribution .svg-icon-24 { width: 16px; height: 16px; flex-shrink: 0; }

/* Layout edit mode polish */
body#layout .container, body#layout .container-narrow { padding: 16px; }
body#layout .sidebar { display: block; }
body#layout .home-grid, body#layout .post-layout, body#layout .page-outer { display: block; }
body#layout .page-outer > .sidebar { display: block; }

body.script:
//
/* Theme toggle */
var cmOsQuery = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)');
function cmApplyTheme(mode){
  var resolved = mode === 'system'
    ? (cmOsQuery && cmOsQuery.matches ? 'dark' : 'light')
    : mode;
  document.documentElement.setAttribute('data-theme', resolved);
}
function cmSetTheme(mode){
  if (mode === 'system') {
    try { localStorage.removeItem('cm-theme'); } catch(e){}
  } else {
    try { localStorage.setItem('cm-theme', mode); } catch(e){}
  }
  cmApplyTheme(mode);
  cmPaintThemeSwitch();
}
function cmPaintThemeSwitch(){
  var saved = (function(){ try { return localStorage.getItem('cm-theme'); } catch(e){ return null; } })();
  var active = saved || 'system';
  document.querySelectorAll('.theme-switch button').forEach(function(b){
    b.classList.toggle('is-active', b.getAttribute('data-mode') === active);
  });
}
/* Live OS preference changes — only applies when user hasn't set an explicit choice */
if (cmOsQuery && cmOsQuery.addEventListener) {
  cmOsQuery.addEventListener('change', function(e){
    try { if (localStorage.getItem('cm-theme')) return; } catch(ex){}
    document.documentElement.setAttribute('data-theme', e.matches ? 'dark' : 'light');
  });
}

/* Search overlay */
function cmOpenSearch(){
  var o = document.getElementById('search-overlay');
  if (!o) return;
  o.classList.add('is-open');
  var i = o.querySelector('input');
  if (i) setTimeout(function(){ i.focus(); }, 50);
}
function cmCloseSearch(){
  var o = document.getElementById('search-overlay');
  if (o) o.classList.remove('is-open');
}
document.addEventListener('keydown', function(e){
  var tag = (document.activeElement && document.activeElement.tagName) || '';
  if (e.key === '/' && tag !== 'INPUT' && tag !== 'TEXTAREA'){
    e.preventDefault(); cmOpenSearch();
  } else if (e.key === 'Escape'){
    cmCloseSearch();
  }
});

/* Reading-time estimate */
function cmReadTime(){
  var body = document.querySelector('.post-body');
  var slot = document.getElementById('read-time');
  if (!body || !slot) return;
  var words = (body.innerText || '').trim().split(/\s+/).length;
  var mins = Math.max(1, Math.round(words / 220));
  slot.textContent = mins + ' min read';
}
document.querySelectorAll('.post-card .read-time').forEach(function(s){
  var w = (s.getAttribute('data-words') || '').split(/\s+/).length;
  s.textContent = Math.max(1, Math.round(w / 220)) + ' min read';
});

/* Decorate <pre> with code-block chrome + copy */
function cmDecorateCode(){
  document.querySelectorAll('.post-body pre').forEach(function(pre){
    if (pre.parentElement && pre.parentElement.classList.contains('code-block')) return;
    var lang = '';
    var codeEl = pre.querySelector('code');
    if (codeEl){
      var m = (codeEl.className || '').match(/language-([a-z0-9]+)/i);
      if (m) lang = m[1];
    }
    var wrap = document.createElement('div');
    wrap.className = 'code-block';
    var head = document.createElement('div');
    head.className = 'code-block-head';
    head.innerHTML =
      '<div class="dots"><span></span><span></span><span></span></div>' +
      (lang ? '<span class="lang">' + lang + '</span>' : '<span></span>') +
      '<button class="copy-btn" type="button">⧉ copy</button>';
    pre.parentNode.insertBefore(wrap, pre);
    wrap.appendChild(head);
    wrap.appendChild(pre);
    head.querySelector('.copy-btn').addEventListener('click', function(){
      var t = pre.innerText;
      if (navigator.clipboard) navigator.clipboard.writeText(t);
      this.textContent = '✓ copied';
      var btn = this;
      setTimeout(function(){ btn.textContent = '⧉ copy'; }, 1400);
    });
  });
}

/* Build TOC from h2/h3 in post body */
function cmBuildTOC(){
  var list = document.getElementById('post-toc-list');
  var body = document.querySelector('.post-body');
  if (!list || !body) return;
  var heads = body.querySelectorAll('h2, h3');
  if (heads.length < 2) {
    var layout = document.querySelector('.post-layout');
    if (layout) layout.classList.add('no-toc');
    return;
  }
  heads.forEach(function(h, i){
    if (!h.id) h.id = 'h-' + i + '-' + (h.textContent || '').toLowerCase().replace(/[^a-z0-9]+/g,'-').slice(0, 32);
    var li = document.createElement('li');
    li.textContent = h.textContent;
    li.style.marginLeft = h.tagName === 'H3' ? '12px' : '0';
    li.addEventListener('click', function(){
      h.scrollIntoView({behavior: 'smooth', block: 'start'});
    });
    list.appendChild(li);
  });
}

/* Reading-progress bar */
function cmProgress(){
  var fill = document.getElementById('progress-fill');
  if (!fill) return;
  var body = document.querySelector('.post-body');
  if (!body) return;
  function tick(){
    var rect = body.getBoundingClientRect();
    var total = rect.height - window.innerHeight;
    var scrolled = -rect.top;
    var pct = Math.max(0, Math.min(1, scrolled / Math.max(1, total)));
    fill.style.width = (pct * 100).toFixed(1) + '%';
    var list = document.getElementById('post-toc-list');
    if (list){
      var items = list.querySelectorAll('li');
      var heads = document.querySelectorAll('.post-body h2, .post-body h3');
      var idx = 0;
      heads.forEach(function(h, i){
        if (h.getBoundingClientRect().top < 120) idx = i;
      });
      items.forEach(function(li, i){ li.classList.toggle('is-active', i === idx); });
    }
  }
  tick();
  window.addEventListener('scroll', tick, { passive: true });
}

/* Adjacent reading via RSS */
function cmLoadAdjacent(){
  var grid = document.getElementById('adjacent-grid');
  if (!grid) return;
  var feed = (window.location.origin || '') + '/feeds/posts/default?alt=json-in-script&max-results=5&callback=cmAdjacent';
  var s = document.createElement('script');
  s.src = feed;
  document.body.appendChild(s);
}
window.cmAdjacent = function(data){
  var grid = document.getElementById('adjacent-grid');
  if (!grid || !data || !data.feed || !data.feed.entry) return;
  var entries = data.feed.entry;
  var here = window.location.href.split('?')[0];
  var out = [];
  for (var i = 0; i < entries.length && out.length < 3; i++){
    var e = entries[i];
    var url = '#'; var title = (e.title && e.title.$t) || '';
    for (var j = 0; j < e.link.length; j++){ if (e.link[j].rel === 'alternate'){ url = e.link[j].href; break; } }
    if (url === here) continue;
    var d = new Date(e.published.$t);
    var date = d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    out.push(
      '<a class="adjacent-card" href="' + url + '">' +
        '<div class="meta"><span>' + date + '</span></div>' +
        '<h4>' + title + '</h4>' +
        '<span class="read">read →</span>' +
      '</a>'
    );
  }
  grid.innerHTML = out.join('');
};

/* Boot */
document.addEventListener('DOMContentLoaded', function(){
  cmPaintThemeSwitch();
  cmReadTime();
  cmDecorateCode();
  cmBuildTOC();
  cmProgress();
  cmLoadAdjacent();

  /* Remove the featured image Blogger auto-inserts into the body,
     since we already render it as a full-width cover above the post. */
  (function() {
    var cover = document.querySelector('.post-cover img');
    if (!cover) return;
    var m = cover.src.match(/\/([A-Za-z0-9_-]{40,})\//);
    if (!m) return;
    var imgId = m[1];
    document.querySelectorAll('.post-body img').forEach(function(img) {
      if (img.src.indexOf(imgId) !== -1) {
        var p = img.closest('p') || img.parentElement;
        p.style.display = 'none';
      }
    });
  })();
});
//
